package core

import (
	"bytes"
	"encoding/hex"
	"testing"
)

func mustHex(s string) []byte {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic(err)
	}
	return b
}

// All expected values in this file were generated by the Python LXMF/RNS
// reference implementation (gen_vectors.py).

func TestFullHash(t *testing.T) {
	input := mustHex("68656c6c6f206c786d66") // b"hello lxmf"
	expected := mustHex("4c43d1dca6a11689d4c33620b86605828f6a651e645c2896647f861118deb4d4")
	got := fullHash(input)
	if !bytes.Equal(got, expected) {
		t.Errorf("fullHash mismatch\n  got:  %x\n  want: %x", got, expected)
	}
}

func TestTruncatedHash(t *testing.T) {
	input := mustHex("68656c6c6f206c786d66")
	expected := mustHex("4c43d1dca6a11689d4c33620b8660582")
	got := TruncatedHash(input)
	if !bytes.Equal(got, expected) {
		t.Errorf("TruncatedHash mismatch\n  got:  %x\n  want: %x", got, expected)
	}
}

func TestHKDF(t *testing.T) {
	material := mustHex("746573745f6d6174657269616c5f666f725f686b6466")
	salt := mustHex("f7089d74bf224cc21fb8191bafefe24d80709bf2e598d0e8dd9648e599cfe594")
	expected := mustHex("894d2f520d6aca920542e03cf9623b3a8d6153ba6997d3360842fb4a81eab89c691fe9268279061c51c51691ff434205d94eafa891726be0bbee4ce2b7e1d58f")

	got := hkdf(64, material, salt, nil)
	if !bytes.Equal(got, expected) {
		t.Errorf("hkdf mismatch\n  got:  %x\n  want: %x", got, expected)
	}
}

func TestStampWorkblock(t *testing.T) {
	material := mustHex("a67a5879c32eef0408395f7db5f78c84efe80754fe869caa2c95b2275a162a49")
	expected := mustHex("")

	got := StampWorkblock(material, 3)
	if len(got) != 768 {
		t.Fatalf("workblock length = %d, want 768", len(got))
	}
	if !bytes.Equal(got, expected) {
		t.Errorf("StampWorkblock mismatch\n  got:  %x\n  want: %x", got[:64], expected[:64])
	}
}

func TestStampValue(t *testing.T) {
	material := mustHex("a67a5879c32eef0408395f7db5f78c84efe80754fe869caa2c95b2275a162a49")
	wb := StampWorkblock(material, 3)
	stamp := mustHex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")

	// Verify the intermediate hash matches Python.
	combined := append(wb, stamp...)
	resultHash := fullHash(combined)
	expectedHash := mustHex("32af9c08479f121b360de566e14771b17d9c5bbf656a1f6ef52c1b238fa97ac7")
	if !bytes.Equal(resultHash, expectedHash) {
		t.Errorf("result hash mismatch\n  got:  %x\n  want: %x", resultHash, expectedHash)
	}

	got := StampValue(wb, stamp)
	if got != 2 {
		t.Errorf("StampValue = %d, want 2", got)
	}
}

func TestStampValid(t *testing.T) {
	material := mustHex("a67a5879c32eef0408395f7db5f78c84efe80754fe869caa2c95b2275a162a49")
	wb := StampWorkblock(material, 3)
	stamp := mustHex("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")

	// The stamp has value=2, so it should be valid at cost 1 and 2, but not 3.
	if !StampValid(stamp, 1, wb) {
		t.Error("StampValid(cost=1) should be true")
	}
	if !StampValid(stamp, 2, wb) {
		t.Error("StampValid(cost=2) should be true")
	}
	if StampValid(stamp, 3, wb) {
		t.Error("StampValid(cost=3) should be false")
	}
}

func TestTicketStamp(t *testing.T) {
	ticket := mustHex("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
	messageID := mustHex("2d44d28ae7059f42e80b49ae456e4b1d55adfce523a393e1ddfa6e5a90a4cc22")
	expected := mustHex("6f08e3d7eef2c2deed3165c4b885547e")

	got := TruncatedHash(append(ticket, messageID...))
	if !bytes.Equal(got, expected) {
		t.Errorf("ticket stamp mismatch\n  got:  %x\n  want: %x", got, expected)
	}
}

func TestValidateStampWithTicket(t *testing.T) {
	ticket := mustHex("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
	messageHash := mustHex("2d44d28ae7059f42e80b49ae456e4b1d55adfce523a393e1ddfa6e5a90a4cc22")
	ticketStamp := mustHex("6f08e3d7eef2c2deed3165c4b885547e")

	msg := &LXMessage{
		Hash:  messageHash,
		Stamp: ticketStamp,
	}

	valid, value := ValidateStamp(msg, 16, [][]byte{ticket})
	if !valid {
		t.Error("ValidateStamp with ticket should return true")
	}
	if value != CostTicket {
		t.Errorf("ValidateStamp value = %d, want %d (CostTicket)", value, CostTicket)
	}
}

func TestValidateStampWithPoW(t *testing.T) {
	messageHash := mustHex("2d44d28ae7059f42e80b49ae456e4b1d55adfce523a393e1ddfa6e5a90a4cc22")
	stamp := mustHex("1ad13bbeb7ffdd00cc2143a08382a0763966b49930a8475498f9e18c47f721cf")

	msg := &LXMessage{
		Hash:  messageHash,
		Stamp: stamp,
	}

	valid, value := ValidateStamp(msg, 1, nil)
	if !valid {
		t.Error("ValidateStamp with PoW stamp should return true at cost=1")
	}
	if value < 1 {
		t.Errorf("stamp value = %d, want >= 1", value)
	}
}
